import React, { useState } from 'react';
import { ExternalLink, Github, Filter } from 'lucide-react';

/**
 * Project data array
 * Each project has a title, description, tech stack, category tags, and optional links
 */
const projectsData = [
  {
    id: 1,
    title: 'TaskFlow',
    description:
      'A collaborative task management app with real-time updates, drag-and-drop boards, and team workspaces.',
    tech: ['React', 'TypeScript', 'Firebase', 'Tailwind CSS'],
    category: ['Web Development'],
    github: 'https://github.com',
    live: 'https://example.com',
  },
  {
    id: 2,
    title: 'WeatherNow',
    description:
      'A native Android weather application featuring location-based forecasts, interactive radar maps, and severe weather alerts.',
    tech: ['Kotlin', 'Android', 'Retrofit', 'Jetpack Compose'],
    category: ['Mobile Apps'],
    github: 'https://github.com',
    live: null,
  },
  {
    id: 3,
    title: 'DataPulse',
    description:
      'An open-source Python library for automated data profiling, cleaning, and visualization with a simple CLI interface.',
    tech: ['Python', 'Pandas', 'Matplotlib', 'CLI'],
    category: ['Open Source'],
    github: 'https://github.com',
    live: null,
  },
  {
    id: 4,
    title: 'DevBlog',
    description:
      'A static blog generator for developers with Markdown support, syntax highlighting, and SEO optimization.',
    tech: ['React', 'Next.js', 'MDX', 'Vercel'],
    category: ['Web Development', 'Open Source'],
    github: 'https://github.com',
    live: 'https://example.com',
  },
  {
    id: 5,
    title: 'FitnessTrack',
    description:
      'Cross-platform fitness tracking app with workout logging, progress charts, and social challenges.',
    tech: ['React Native', 'TypeScript', 'Node.js', 'MongoDB'],
    category: ['Mobile Apps'],
    github: 'https://github.com',
    live: 'https://example.com',
  },
  {
    id: 6,
    title: 'ConfigKit',
    description:
      'A lightweight, zero-dependency JavaScript utility for managing environment configs across multiple deployment targets.',
    tech: ['JavaScript', 'Node.js', 'npm', 'TypeScript'],
    category: ['Open Source'],
    github: 'https://github.com',
    live: null,
  },
  {
    id: 7,
    title: 'Portfolio CMS',
    description:
      'A headless CMS for developers to manage portfolio content with a visual editor and API-first architecture.',
    tech: ['React', 'Python', 'FastAPI', 'PostgreSQL'],
    category: ['Web Development'],
    github: 'https://github.com',
    live: 'https://example.com',
  },
  {
    id: 8,
    title: 'SnapNote',
    description:
      'An iOS note-taking app with handwriting recognition, markdown export, and iCloud sync.',
    tech: ['Swift', 'UIKit', 'CoreML', 'CloudKit'],
    category: ['Mobile Apps'],
    github: 'https://github.com',
    live: null,
  },
];

/**
 * Available filter categories for the project grid
 */
const filterCategories = ['All', 'Mobile Apps', 'Web Development', 'Open Source'];

/**
 * TechStackBadge Component
 * Renders a colored badge for each technology in the stack
 */
const TechStackBadge = ({ tech }) => {
  // Map common tech names to accent colors for visual variety
  const colorMap = {
    React: 'bg-cyan-500/10 text-cyan-400 border-cyan-500/20',
    'React Native': 'bg-cyan-500/10 text-cyan-400 border-cyan-500/20',
    TypeScript: 'bg-blue-500/10 text-blue-400 border-blue-500/20',
    JavaScript: 'bg-yellow-500/10 text-yellow-400 border-yellow-500/20',
    Kotlin: 'bg-purple-500/10 text-purple-400 border-purple-500/20',
    Android: 'bg-green-500/10 text-green-400 border-green-500/20',
    Python: 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20',
    Swift: 'bg-orange-500/10 text-orange-400 border-orange-500/20',
    Node: 'bg-lime-500/10 text-lime-400 border-lime-500/20',
  };

  // Find matching color or use default indigo
  const colorClass =
    Object.entries(colorMap).find(([key]) =>
      tech.toLowerCase().includes(key.toLowerCase())
    )?.[1] || 'bg-indigo-500/10 text-indigo-400 border-indigo-500/20';

  return (
    <span
      className={`inline-block px-2.5 py-1 text-xs font-medium rounded-md border ${colorClass} transition-colors duration-200`}
    >
      {tech}
    </span>
  );
};

/**
 * ProjectCard Component
 * Individual project card with hover animations, tech badges, and action links
 */
const ProjectCard = ({ project, index }) => {
  return (
    <div
      className="group relative bg-slate-900/50 border border-slate-800/50 rounded-2xl p-6 flex flex-col transition-all duration-300 hover:bg-slate-800/50 hover:border-slate-700/50 hover:shadow-xl hover:shadow-indigo-500/5 hover:-translate-y-1 animate-slide-up"
      style={{ animationDelay: `${index * 0.05}s` }}
    >
      {/* Card Header */}
      <div className="flex items-start justify-between mb-4">
        <h3 className="text-xl font-semibold text-white group-hover:text-indigo-400 transition-colors duration-200">
          {project.title}
        </h3>
        <div className="flex items-center gap-2">
          {/* GitHub link */}
          {project.github && (
            <a
              href={project.github}
              target="_blank"
              rel="noopener noreferrer"
              className="p-2 rounded-lg text-slate-500 hover:text-white hover:bg-slate-800 transition-all duration-200"
              aria-label={`View ${project.title} source code`}
            >
              <Github size={18} />
            </a>
          )}
          {/* Live demo link */}
          {project.live && (
            <a
              href={project.live}
              target="_blank"
              rel="noopener noreferrer"
              className="p-2 rounded-lg text-slate-500 hover:text-emerald-400 hover:bg-slate-800 transition-all duration-200"
              aria-label={`View ${project.title} live demo`}
            >
              <ExternalLink size={18} />
            </a>
          )}
        </div>
      </div>

      {/* Description */}
      <p className="text-slate-400 text-sm leading-relaxed mb-5 flex-grow">
        {project.description}
      </p>

      {/* Tech Stack Badges */}
      <div className="flex flex-wrap gap-2">
        {project.tech.map((t) => (
          <TechStackBadge key={t} tech={t} />
        ))}
      </div>

      {/* Hover glow effect (subtle gradient border on hover) */}
      <div className="absolute inset-0 rounded-2xl bg-gradient-to-br from-indigo-500/5 via-transparent to-emerald-500/5 opacity-0 group-hover:opacity-100 transition-opacity duration-300 pointer-events-none" />
    </div>
  );
};

/**
 * Projects Section Component
 * Displays a filterable grid of project cards
 * Includes category filter tags at the top
 */
const Projects = () => {
  const [activeFilter, setActiveFilter] = useState('All');

  // Filter projects based on the active category
  const filteredProjects =
    activeFilter === 'All'
      ? projectsData
      : projectsData.filter((p) => p.category.includes(activeFilter));

  return (
    <section id="projects" className="py-24 px-6">
      <div className="max-w-6xl mx-auto">
        {/* Section Header */}
        <div className="text-center mb-14">
          <h2 className="text-3xl sm:text-4xl font-bold text-white mb-4">
            Featured Projects
          </h2>
          <p className="text-slate-400 max-w-xl mx-auto">
            A selection of projects spanning mobile, web, and open-source contributions.
          </p>
        </div>

        {/* Filter Tags */}
        <div className="flex items-center justify-center gap-3 mb-12 flex-wrap">
          <Filter size={16} className="text-slate-500" />
          {filterCategories.map((cat) => (
            <button
              key={cat}
              onClick={() => setActiveFilter(cat)}
              className={`px-4 py-2 text-sm font-medium rounded-lg transition-all duration-200 ${
                activeFilter === cat
                  ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-500/25'
                  : 'bg-slate-800/50 text-slate-400 border border-slate-700/50 hover:text-white hover:bg-slate-800 hover:border-slate-600'
              }`}
            >
              {cat}
            </button>
          ))}
        </div>

        {/* Project Grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {filteredProjects.map((project, index) => (
            <ProjectCard key={project.id} project={project} index={index} />
          ))}
        </div>

        {/* Empty state when no projects match filter */}
        {filteredProjects.length === 0 && (
          <div className="text-center py-16 text-slate-500">
            No projects found for this category.
          </div>
        )}
      </div>
    </section>
  );
};

export default Projects;
